import boto3
from getpass import getpass
from botocore.exceptions import ClientError

sns = boto3.client('sns')

def create_subscription(topic_arn):
    user_input = input("Please enter the URL to subscribe: ")
    try:
        response = sns.subscribe(
            TopicArn=topic_arn,
            Protocol='https',
            Endpoint=user_input
        )
        print(response)
    except ClientError as e:
        print(f"Subscription failed with error: {e}")

def main():
    topic_name = input("Please enter the SNS topic name: ")
    topic_arn = f'arn:aws:sns:{region}:123456789012:{topic_name}'
    
    # For security reasons, do not hard code AWS credentials
    aws_access_key_id = getpass('AWS access key ID: ')
    aws_secret_access_key = getpass('AWS secret access key: ')

    sns = boto3.client(
        'sns',
        region_name='region',  # Please enter your AWS Region here
        aws_access_key_id=aws_access_key_id,
        aws_secret_access_key=aws_secret_access_key
    )

    while True:
        print("\nChoose an option:")
        print("1: Subscribe to SNS topic")
        print("2: Exit")
        
        choice = input("Enter your choice (1/2): ")
        
        if choice == '1':
            create_subscription(topic_arn)
        elif choice == '2':
            break
        else:
            print("Invalid option. Please try again.")

if __name__ == "__main__":
    main()